import{_ as n,o as i,c as a,ag as t}from"./chunks/framework.CvgP6Fyv.js";const d=JSON.parse('{"title":"Geschäftsseite","description":"","frontmatter":{},"headers":[],"relativePath":"de/advanced/business-page.md","filePath":"de/advanced/business-page.md"}'),r={name:"de/advanced/business-page.md"};function s(l,e,o,h,g,u){return i(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="geschaftsseite" tabindex="-1">Geschäftsseite <a class="header-anchor" href="#geschaftsseite" aria-label="Permalink to &quot;Geschäftsseite&quot;">​</a></h1><p>Erstellen Sie ein öffentliches Profil für Ihr Unternehmen, das Kunden besuchen können, um mehr über Ihre Dienstleistungen zu erfahren und Angebote anzufragen.</p><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><p>Ihre Geschäftsseite ist eine öffentliche Webseite, die präsentiert:</p><ul><li>Ihre Unternehmensinformationen</li><li>Angebotene Dienstleistungen</li><li>Kontaktdaten</li><li>Social-Media-Links</li><li>Ein Angebotsanfrageformular</li></ul><h2 id="geschaftsseite-einrichten" tabindex="-1">Geschäftsseite einrichten <a class="header-anchor" href="#geschaftsseite-einrichten" aria-label="Permalink to &quot;Geschäftsseite einrichten&quot;">​</a></h2><ol><li>Gehen Sie zu den <strong>Unternehmens</strong>-Einstellungen</li><li>Füllen Sie den Bereich <strong>Geschäftsprofil</strong> aus: <ul><li><strong>Beschreibung</strong> — Ein kurzer Überblick über Ihr Unternehmen</li><li><strong>Dienstleistungen</strong> — Listen Sie die Dienstleistungen auf, die Sie anbieten</li><li><strong>Website</strong> — Die URL Ihrer Firmenwebsite</li><li><strong>Social Media</strong> — Links zu Ihren sozialen Profilen</li></ul></li><li>Ihre Geschäftsseite ist automatisch unter einer eindeutigen URL verfügbar</li></ol><h2 id="geschaftsseiten-url" tabindex="-1">Geschäftsseiten-URL <a class="header-anchor" href="#geschaftsseiten-url" aria-label="Permalink to &quot;Geschäftsseiten-URL&quot;">​</a></h2><p>Ihre Seite ist erreichbar unter:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://app.mycompanydesk.com/portal/{ihr-firmen-slug}</span></span></code></pre></div><p>Teilen Sie diesen Link auf Ihrer Website, in sozialen Medien oder auf Visitenkarten.</p><h2 id="angebotsanfrageformular" tabindex="-1">Angebotsanfrageformular <a class="header-anchor" href="#angebotsanfrageformular" aria-label="Permalink to &quot;Angebotsanfrageformular&quot;">​</a></h2><p>Besucher Ihrer Geschäftsseite können eine Angebotsanfrage einreichen:</p><ol><li>Sie füllen ihren <strong>Namen</strong>, ihre <strong>E-Mail</strong> und eine <strong>Dienstleistungsbeschreibung</strong> aus</li><li>Die Anfrage wird eingereicht</li><li>Sie erhalten eine Benachrichtigung</li><li>Die Anfrage erscheint unter <strong>Angebote &gt; Anfragen</strong></li></ol><h3 id="ratenbegrenzung" tabindex="-1">Ratenbegrenzung <a class="header-anchor" href="#ratenbegrenzung" aria-label="Permalink to &quot;Ratenbegrenzung&quot;">​</a></h3><p>Um Spam zu verhindern, sind Angebotsanfragen auf 1 pro 15 Minuten pro IP-Adresse begrenzt.</p><h2 id="anfragen-verwalten" tabindex="-1">Anfragen verwalten <a class="header-anchor" href="#anfragen-verwalten" aria-label="Permalink to &quot;Anfragen verwalten&quot;">​</a></h2><p>Siehe <a href="/de/features/quotes#angebotsanfragen">Angebote — Angebotsanfragen</a> für Details zur Verwaltung eingehender Anfragen.</p><h2 id="branding" tabindex="-1">Branding <a class="header-anchor" href="#branding" aria-label="Permalink to &quot;Branding&quot;">​</a></h2><p>Ihre Geschäftsseite verwendet Ihr Unternehmensbranding:</p><ul><li>Firmenlogo</li><li>Akzentfarbe</li><li>Firmenname und Details</li></ul><h2 id="tipps" tabindex="-1">Tipps <a class="header-anchor" href="#tipps" aria-label="Permalink to &quot;Tipps&quot;">​</a></h2><ul><li>Halten Sie Ihre Dienstleistungsliste aktuell</li><li>Fügen Sie einen Link zu Ihrer Geschäftsseite auf Ihrer Website hinzu</li><li>Antworten Sie zeitnah auf Angebotsanfragen für eine bessere Konversionsrate</li><li>Verwenden Sie den Angebotsanfrage-Workflow, um Leads zu verfolgen</li></ul>',23)])])}const f=n(r,[["render",s]]);export{d as __pageData,f as default};
